// App.js
import React, { useState, useEffect, createContext, useContext } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  ActivityIndicator,
  Alert,
  SafeAreaView,
  Image,
} from 'react-native';
import * as AuthSession from 'expo-auth-session';
import * as WebBrowser from 'expo-web-browser';
import * as SecureStore from 'expo-secure-store';
import * as Crypto from 'expo-crypto';

WebBrowser.maybeCompleteAuthSession();

// ============================================================
// SECURITY NOTE:
// - client_id is acceptable in mobile apps (it's a public identifier)
// - client_secret must NEVER be embedded in mobile/client-side code
// - We use PKCE flow which eliminates the need for a client_secret
// - If your backend requires a client_secret for token exchange,
//   proxy that exchange through YOUR backend server
// ============================================================

const AUTH_CONFIG = {
  clientId: 'mobile_app_client_123',
  // NO client_secret here — this is intentional and correct!
  authorizationEndpoint: 'https://your-auth-server.com/oauth/authorize',
  tokenEndpoint: 'https://your-auth-server.com/oauth/token',
  // If you need a backend proxy for token exchange:
  backendTokenProxyEndpoint: 'https://your-api-server.com/auth/token-exchange',
  redirectUri: AuthSession.makeRedirectUri({
    scheme: 'myapp',
    path: 'auth/callback',
  }),
  scopes: ['openid', 'profile', 'email', 'offline_access'],
};

const SECURE_STORE_KEYS = {
  ACCESS_TOKEN: 'auth_access_token',
  REFRESH_TOKEN: 'auth_refresh_token',
  TOKEN_EXPIRY: 'auth_token_expiry',
  USER_PROFILE: 'auth_user_profile',
};

// --- PKCE Utilities ---

async function generateCodeVerifier() {
  const randomBytes = await Crypto.getRandomBytesAsync(32);
  return base64URLEncode(randomBytes);
}

async function generateCodeChallenge(verifier) {
  const digest = await Crypto.digestStringAsync(
    Crypto.CryptoDigestAlgorithm.SHA256,
    verifier,
    { encoding: Crypto.CryptoEncoding.BASE64 }
  );
  return base64URLEncodeString(digest);
}

function base64URLEncode(buffer) {
  const bytes = new Uint8Array(buffer);
  let str = '';
  for (let i = 0; i < bytes.length; i++) {
    str += String.fromCharCode(bytes[i]);
  }
  return btoa(str).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

function base64URLEncodeString(str) {
  return str.replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

function generateState() {
  const array = new Uint8Array(16);
  for (let i = 0; i < array.length; i++) {
    array[i] = Math.floor(Math.random() * 256);
  }
  return base64URLEncode(array);
}

// --- Secure Token Storage ---

class TokenStorage {
  static async saveTokens({ accessToken, refreshToken, expiresIn }) {
    const expiry = Date.now() + expiresIn * 1000;
    await Promise.all([
      SecureStore.setItemAsync(SECURE_STORE_KEYS.ACCESS_TOKEN, accessToken),
      refreshToken
        ? SecureStore.setItemAsync(SECURE_STORE_KEYS.REFRESH_TOKEN, refreshToken)
        : Promise.resolve(),
      SecureStore.setItemAsync(SECURE_STORE_KEYS.TOKEN_EXPIRY, expiry.toString()),
    ]);
  }

  static async getAccessToken() {
    const [token, expiry] = await Promise.all([
      SecureStore.getItemAsync(SECURE_STORE_KEYS.ACCESS_TOKEN),
      SecureStore.getItemAsync(SECURE_STORE_KEYS.TOKEN_EXPIRY),
    ]);

    if (!token || !expiry) return null;

    if (Date.now() >= parseInt(expiry, 10) - 60000) {
      return null; // Token expired or about to expire
    }

    return token;
  }

  static async getRefreshToken() {
    return SecureStore.getItemAsync(SECURE_STORE_KEYS.REFRESH_TOKEN);
  }

  static async saveUserProfile(profile) {
    await SecureStore.setItemAsync(
      SECURE_STORE_KEYS.USER_PROFILE,
      JSON.stringify(profile)
    );
  }

  static async getUserProfile() {
    const data = await SecureStore.getItemAsync(SECURE_STORE_KEYS.USER_PROFILE);
    return data ? JSON.parse(data) : null;
  }

  static async clearAll() {
    await Promise.all(
      Object.values(SECURE_STORE_KEYS).map((key) =>
        SecureStore.deleteItemAsync(key)
      )
    );
  }
}

// --- Auth Service ---

class AuthService {
  // Option A: Direct PKCE token exchange (no client_secret needed)
  static async exchangeCodeForTokensPKCE(code, codeVerifier) {
    const body = new URLSearchParams({
      grant_type: 'authorization_code',
      client_id: AUTH_CONFIG.clientId,
      code,
      redirect_uri: AUTH_CONFIG.redirectUri,
      code_verifier: codeVerifier,
      // NO client_secret — PKCE replaces it
    });

    const response = await fetch(AUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: body.toString(),
    });

    if (!response.ok) {
      const error = await response.json().catch(() => ({}));
      throw new Error(error.error_description || 'Token exchange failed');
    }

    return response.json();
  }

  // Option B: Backend proxy token exchange
  // Use this if your auth server strictly requires a client_secret.
  // The secret lives ONLY on your backend server.
  static async exchangeCodeViaBackendProxy(code, codeVerifier) {
    const response = await fetch(AUTH_CONFIG.backendTokenProxyEndpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        code,
        code_verifier: codeVerifier,
        redirect_uri: AUTH_CONFIG.redirectUri,
      }),
    });

    if (!response.ok) {
      const error = await response.json().catch(() => ({}));
      throw new Error(error.error_description || 'Token exchange failed');
    }

    return response.json();
  }

  static async refreshAccessToken() {
    const refreshToken = await TokenStorage.getRefreshToken();
    if (!refreshToken) throw new Error('No refresh token available');

    // PKCE-based refresh (no client_secret needed)
    const body = new URLSearchParams({
      grant_type: 'refresh_token',
      client_id: AUTH_CONFIG.clientId,
      refresh_token: refreshToken,
    });

    const response = await fetch(AUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: body.toString(),
    });

    if (!response.ok) {
      throw new Error('Token refresh failed');
    }

    const tokens = await response.json();
    await TokenStorage.saveTokens({
      accessToken: tokens.access_token,
      refreshToken: tokens.refresh_token,
      expiresIn: tokens.expires_in,
    });

    return tokens.access_token;
  }

  static async fetchUserProfile(accessToken) {
    const response = await fetch('https://your-auth-server.com/oauth/userinfo', {
      headers: { Authorization: `Bearer ${accessToken}` },
    });

    if (!response.ok) throw new Error('Failed to fetch user profile');
    return response.json();
  }
}

// --- Authenticated API Client ---

class ApiClient {
  static async fetch(url, options = {}) {
    let accessToken = await TokenStorage.getAccessToken();

    if (!accessToken) {
      try {
        accessToken = await AuthService.refreshAccessToken();
      } catch {
        throw new Error('SESSION_EXPIRED');
      }
    }

    const response = await fetch(url, {
      ...options,
      headers: {
        ...options.headers,
        Authorization: `Bearer ${accessToken}`,
      },
    });

    if (response.status === 401) {
      try {
        accessToken = await AuthService.refreshAccessToken();
        return fetch(url, {
          ...options,
          headers: {
            ...options.headers,
            Authorization: `Bearer ${accessToken}`,
          },
        });
      } catch {
        throw new Error('SESSION_EXPIRED');
      }
    }

    return response;
  }
}

// --- Auth Context ---

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [state, setState] = useState({
    isLoading: true,
    isAuthenticated: false,
    user: null,
    error: null,
  });

  const [codeVerifier, setCodeVerifier] = useState(null);

  useEffect(() => {
    checkExistingSession();
  }, []);

  async function checkExistingSession() {
    try {
      const token = await TokenStorage.getAccessToken();
      if (token) {
        const user = await TokenStorage.getUserProfile();
        setState({
          isLoading: false,
          isAuthenticated: true,
          user,
          error: null,
        });
      } else {
        const refreshToken = await TokenStorage.getRefreshToken();
        if (refreshToken) {
          try {
            const newToken = await AuthService.refreshAccessToken();
            const user = await AuthService.fetchUserProfile(newToken);
            await TokenStorage.saveUserProfile(user);
            setState({
              isLoading: false,
              isAuthenticated: true,
              user,
              error: null,
            });
            return;
          } catch {
            await TokenStorage.clearAll();
          }
        }
        setState({
          isLoading: false,
          isAuthenticated: false,
          user: null,
          error: null,
        });
      }
    } catch {
      setState({
        isLoading: false,
        isAuthenticated: false,
        user: null,
        error: null,
      });
    }
  }

  async function login() {
    try {
      setState((prev) => ({ ...prev, error: null, isLoading: true }));

      // Generate PKCE parameters
      const verifier = await generateCodeVerifier();
      const challenge = await generateCodeChallenge(verifier);
      const stateParam = generateState();

      setCodeVerifier(verifier);

      const authUrl =
        `${AUTH_CONFIG.authorizationEndpoint}?` +
        new URLSearchParams({
          response_type: 'code',
          client_id: AUTH_CONFIG.clientId,
          redirect_uri: AUTH_CONFIG.redirectUri,
          scope: AUTH_CONFIG.scopes.join(' '),
          state: stateParam,
          code_challenge: challenge,
          code_challenge_method: 'S256',
        }).toString();

      const result = await WebBrowser.openAuthSessionAsync(
        authUrl,
        AUTH_CONFIG.redirectUri
      );

      if (result.type === 'success' && result.url) {
        const url = new URL(result.url);
        const code = url.searchParams.get('code');
        const returnedState = url.searchParams.get('state');
        const error = url.searchParams.get('error');

        if (error) {
          throw new Error(url.searchParams.get('error_description') || error);
        }

        if (returnedState !== stateParam) {
          throw new Error('State mismatch — possible CSRF attack');
        }

        if (!code) {
          throw new Error('No authorization code received');
        }

        // Exchange code for tokens using PKCE (no secret needed!)
        const tokens = await AuthService.exchangeCodeForTokensPKCE(
          code,
          verifier
        );

        await TokenStorage.saveTokens({
          accessToken: tokens.access_token,
          refreshToken: tokens.refresh_token,
          expiresIn: tokens.expires_in,
        });

        const user = await AuthService.fetchUserProfile(tokens.access_token);
        await TokenStorage.saveUserProfile(user);

        setState({
          isLoading: false,
          isAuthenticated: true,
          user,
          error: null,
        });
      } else {
        setState((prev) => ({ ...prev, isLoading: false }));
      }
    } catch (error) {
      setState((prev) => ({
        ...prev,
        isLoading: false,
        error: error.message,
      }));
      Alert.alert('Authentication Error', error.message);
    }
  }

  async function logout() {
    await TokenStorage.clearAll();
    setState({
      isLoading: false,
      isAuthenticated: false,
      user: null,
      error: null,
    });
  }

  return (
    <AuthContext.Provider value={{ ...state, login, logout, apiClient: ApiClient }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) throw new Error('useAuth must be used within AuthProvider');
  return context;
}

// --- Screens ---

function LoginScreen() {
  const { login, isLoading, error } = useAuth();

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.loginContainer}>
        <Text style={styles.appTitle}>🔐 MyApp</Text>
        <Text style={styles.subtitle}>Secure OAuth 2.0 + PKCE Authentication</Text>

        {error && (
          <View style={styles.errorBanner}>
            <Text style={styles.errorText}>{error}</Text>
          </View>
        )}

        <TouchableOpacity
          style={[styles.loginButton, isLoading && styles.buttonDisabled]}
          onPress={login}
          disabled={isLoading}
        >
          {isLoading ? (
            <ActivityIndicator color="#fff" />
          ) : (
            <Text style={styles.loginButtonText}>Sign In</Text>
          )}
        </TouchableOpacity>

        <Text style={styles.securityNote}>
          🛡️ Secured with PKCE — no secrets stored on device
        </Text>
      </View>
    </SafeAreaView>
  );
}

function HomeScreen() {
  const { user, logout, apiClient } = useAuth();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);

  async function fetchProtectedData() {
    setLoading(true);
    try {
      const response = await apiClient.fetch(
        'https://your-api-server.com/api/data'
      );
      const result = await response.json();
      setData(result);
    } catch (error) {
      if (error.message === 'SESSION_EXPIRED') {
        Alert.alert('Session Expired', 'Please log in again.');
        logout();
      } else {
        Alert.alert('Error', error.message);
      }
    } finally {
      setLoading(false);
    }
  }

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.homeContainer}>
        <Text style={styles.welcomeText}>
          Welcome, {user?.name || user?.email || 'User'}!
        </Text>

        {user?.picture && (
          <Image source={{ uri: user.picture }} style={styles.avatar} />
        )}

        {user?.email && <Text style={styles.emailText}>{user.email}</Text>}

        <TouchableOpacity
          style={styles.actionButton}
          onPress={fetchProtectedData}
          disabled={loading}
        >
          {loading ? (
            <ActivityIndicator color="#fff" />
          ) : (
            <Text style={styles.actionButtonText}>Fetch Protected Data</Text>
          )}
        </TouchableOpacity>

        {data && (
          <View style={styles.dataContainer}>
            <Text style={styles.dataText}>{JSON.stringify(data, null, 2)}</Text>
          </View>
        )}

        <TouchableOpacity style={styles.logoutButton} onPress={logout}>
          <Text style={styles.logoutButtonText}>Sign Out</Text>
        </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
}

function LoadingScreen() {
  return (
    <View style={[styles.container, styles.center]}>
      <ActivityIndicator size="large" color="#4A90D9" />
      <Text style={styles.loadingText}>Loading...</Text>
    </View>
  );
}

// --- Main App ---

export default function App() {
  return (
    <AuthProvider>
      <AppNavigator />
    </AuthProvider>
  );
}

function AppNavigator() {
  const { isLoading, isAuthenticated } = useAuth();

  if (isLoading) return <LoadingScreen />;
  if (isAuthenticated) return <HomeScreen />;
  return <LoginScreen />;
}

